class InputValidator:
    @staticmethod
    def validate_account_number(account_number):
        if not account_number:
            return False, "Account number is required"
        if not re.match(r'^\d{4}$', account_number):
            return False, "Invalid account number format"
        return True, ""

    @staticmethod
    def validate_amount(amount):
        if amount is None:
            return False, "Amount is required"
        try:
            amount_decimal = PyDecimal(str(amount))
            if amount_decimal <= 0:
                return False, "Amount must be greater than zero"
            if amount_decimal > PyDecimal('1000000'):
                return False, "Amount exceeds maximum limit"
            return True, ""
        except:
            return False, "Invalid amount format"

    @staticmethod
    def sanitize_string(input_str, max_length=100):
        if not input_str:
            return ""
        sanitized = re.sub(r'[^\w\s\-\.]', '', str(input_str))
        return sanitized[:max_length]


class FinancialService(ServiceBase):
    @rpc(Unicode, _returns=BalanceResponse)
    def getBalance(ctx, account_number):
        valid, error_msg = InputValidator.validate_account_number(account_number)
        if not valid:
            ctx.transport.resp_code = '500 Internal Server Error'
            raise ValueError(error_msg)

        account = db.get_account(account_number)
        if not account:
            ctx.transport.resp_code = '404 Not Found'
            raise ValueError("Account not found")

        if account['status'] != 'Active':
            ctx.transport.resp_code = '403 Forbidden'
            raise ValueError("Account is not active")

        response = BalanceResponse()
        response.account_number = account_number
        response.balance = account['balance']
        response.currency = 'USD'

        return response

    @rpc(TransferRequest, _returns=TransferResponse)
    def transferFunds(ctx, transfer_request):
        from_account = transfer_request.from_account
        to_account = transfer_request.to_account
        amount = transfer_request.amount
        description = transfer_request.description

        valid, error_msg = InputValidator.validate_account_number(from_account)
        if not valid:
            ctx.transport.resp_code = '400 Bad Request'
            raise ValueError(f"Invalid source account: {error_msg}")

        valid, error_msg = InputValidator.validate_account_number(to_account)
        if not valid:
            ctx.transport.resp_code = '400 Bad Request'
            raise ValueError(f"Invalid destination account: {error_msg}")

        valid, error_msg = InputValidator.validate_amount(amount)
        if not valid:
            ctx.transport.resp_code = '400 Bad Request'
            raise ValueError(error_msg)

        if from_account == to_account:
            ctx.transport.resp_code = '400 Bad Request'
            raise ValueError("Cannot transfer to the same account")

        from_acc = db.get_account(from_account)
        to_acc = db.get_account(to_account)

        if not from_acc:
            ctx.transport.resp_code = '404 Not Found'
            raise ValueError("Source account not found")

        if not to_acc:
            ctx.transport.resp_code = '404 Not Found'
            raise ValueError("Destination account not found")

        if from_acc['status'] != 'Active' or to_acc['status'] != 'Active':
            ctx.transport.resp_code = '403 Forbidden'
            raise ValueError("One or both accounts are not active")

        amount_decimal = PyDecimal(str(amount))

        if from_acc['balance'] < amount_decimal:
            ctx.transport.resp_code = '400 Bad Request'
            raise ValueError("Insufficient funds")

        new_from_balance = from_acc['balance'] - amount_decimal
        new_to_balance = to_acc['balance'] + amount_decimal

        db.update_balance(from_account, new_from_balance)
        db.update_balance(to_account, new_to_balance)

        transaction_id = secrets.token_hex(16)
        timestamp = datetime.now().isoformat()

        transaction = {
            'transaction_id': transaction_id,
            'from_account': from_account,
            'to_account': to_account,
            'amount': amount_decimal,
            'description': InputValidator.sanitize_string(description),
            'timestamp': timestamp
        }
        db.add_transaction(transaction)

        response = TransferResponse()
        response.transaction_id = transaction_id
        response.status = 'SUCCESS'
        response.message = f'Transfer of {amount_decimal} from {from_account} to {to_account} completed successfully'
        response.timestamp = timestamp

        return response

